const data       = $input.first().json;
const issues     = data.issues || [];
const staticData = $getWorkflowStaticData('global');
const processed  = staticData.processedIds || [];

const nuevos = issues.filter(i => !processed.includes(i.id));

const allIds = [...new Set([...processed, ...issues.map(i => i.id)])];
staticData.processedIds = allIds.slice(-500);

const fecha = new Date().toLocaleString('es-CL', { timeZone: 'America/Santiago' });
const date  = new Date().toISOString().split('T')[0];

if (nuevos.length === 0) return [{ json: { skip: true, fecha, date } }];

return nuevos.map(issue => {
  const f = issue.fields || {};
  return { json: {
    key:         issue.key,
    id:          issue.id,
    summary:     (f.summary || '').substring(0, 120),
    description: f.description || null,
    priority:    f.priority?.name  || 'Medium',
    assignee:    f.assignee?.displayName || 'Sin asignar',
    reporter:    f.reporter?.displayName || '',
    issuetype:   f.issuetype?.name || 'Task',
    created:     (f.created || '').substring(0, 10),
    url:         `https://qaprocess1.atlassian.net/browse/${issue.key}`,
    fecha,
    date,
    skip: false
  }};
});

const item = $input.first().json;
const { key, summary, description, priority, assignee, reporter, issuetype, created, url, fecha, date } = item;

function extractText(desc) {
  if (!desc) return null;
  if (typeof desc === 'string') return desc.substring(0, 400);
  try {
    return (desc.content || [])
      .flatMap(b => (b.content || []).map(c => c.text || ''))
      .join(' ').substring(0, 400).trim();
  } catch { return null; }
}

const descText = extractText(description);
const PC = '[Por completar]';

const sdd = {
  titulo:    summary || PC,
  problema:  descText || `${PC} — describir la necesidad de negocio o del usuario`,
  contexto:  `Tipo: ${issuetype}. Proyecto: KAN. Asignado: ${assignee}. Reportado por: ${reporter || PC}. Creado: ${created}.`,
  objetivo:  summary ? `Verificar que el sistema implementa correctamente: ${summary.substring(0, 80)}` : PC,
  alcance: {
    incluye:   [`${PC} — funcionalidad principal`, `${PC} — caso de exito`],
    noIncluye: [`${PC} — integraciones externas`, `${PC} — datos historicos`],
  },
  comportamiento: {
    flujo:     [`${PC} — paso 1`, `${PC} — paso 2`, `${PC} — paso 3`],
    edgeCases: [`${PC} — caso borde 1`, `${PC} — caso borde 2`],
  },
  criterios: [
    `Dado ${PC} Cuando ${PC} Entonces ${PC}`,
    `Dado ${PC} Cuando ${PC} Entonces ${PC}`,
  ],
  restricciones: {
    tecnicas:  `${PC} — ej: tiempo de respuesta menor a 3 segundos`,
    negocio:   `${PC} — ej: reglas de negocio aplicables`,
    seguridad: `${PC} — ej: autenticacion requerida`,
  },
  notas: `Issue: ${key} | Tipo: ${issuetype} | Prioridad: ${priority} | Asignado: ${assignee} | Reportado: ${reporter || 'N/A'} | Creado: ${created} | Link: ${url}`,
};

return [{ json: { ...item, sdd } }];
